// WorkspaceServiceHandler is an implementation of the diag.v1.WorkspaceService service.
type WorkspaceServiceHandler interface {
	// CreateView creates a new view in the given organisation.
	// Required: org_id, name.
	CreateView(context.Context, *connect.Request[v1.CreateViewRequest]) (*connect.Response[v1.CreateViewResponse], error)
	// ApplyPlan atomically upserts elements, canonical views, placements, and
	// connectors in a single PostgreSQL transaction. If any step fails the
	// entire transaction is rolled back. Refs are local names used to wire up
	// cross-references within the plan; they are resolved to IDs by the server
	// and never stored.
	// Required: org_id, at least one resource in elements/connectors.
	ApplyWorkspacePlan(context.Context, *connect.Request[v1.ApplyPlanRequest]) (*connect.Response[v1.ApplyPlanResponse], error)
	// ExportWorkspace fetches all view, element, connector, and navigation data
	// for an organization to allow CLI-based backups and migrations.
	// Required: org_id.
	ExportWorkspace(context.Context, *connect.Request[v1.ExportOrganizationRequest]) (*connect.Response[v1.ExportOrganizationResponse], error)
	// DeleteView permanently removes a view.
	// All connectors and element placements on the view are cascade-deleted by the DB.
	// Required: org_id, view_id. Caller must be an editor.
	DeleteView(context.Context, *connect.Request[v1.DeleteViewRequest]) (*connect.Response[v1.DeleteViewResponse], error)
	// DeleteElement permanently removes an element from the org registry.
	// All placements and connectors referencing it are cascade-deleted by the DB.
	// Required: org_id, element_id. Caller must be an editor.
	DeleteElement(context.Context, *connect.Request[v1.DeleteElementRequest]) (*connect.Response[v1.DeleteElementResponse], error)
	// DeleteConnector removes a single connector from a view.
	// Required: org_id, connector_id. Caller must be an editor.
	DeleteConnector(context.Context, *connect.Request[v1.DeleteConnectorRequest]) (*connect.Response[v1.DeleteConnectorResponse], error)
	// DeleteElementNavigation removes an element-to-view navigation by ID.
	// Required: org_id, navigation_id. Caller must be an editor.
	DeleteElementNavigation(context.Context, *connect.Request[v1.DeleteElementNavigationRequest]) (*connect.Response[v1.DeleteElementNavigationResponse], error)
	// Views
	ListViews(context.Context, *connect.Request[v1.ListViewsRequest]) (*connect.Response[v1.ListViewsResponse], error)
	GetView(context.Context, *connect.Request[v1.GetViewRequest]) (*connect.Response[v1.GetViewResponse], error)
	UpdateView(context.Context, *connect.Request[v1.UpdateViewRequest]) (*connect.Response[v1.UpdateViewResponse], error)
	SetViewLevel(context.Context, *connect.Request[v1.SetViewLevelRequest]) (*connect.Response[v1.SetViewLevelResponse], error)
	GetWorkspace(context.Context, *connect.Request[v1.GetWorkspaceRequest]) (*connect.Response[v1.GetWorkspaceResponse], error)
	ListIncomingElementNavigations(context.Context, *connect.Request[v1.ListIncomingElementNavigationsRequest]) (*connect.Response[v1.ListIncomingElementNavigationsResponse], error)
	// Elements
	ListElements(context.Context, *connect.Request[v1.ListElementsRequest]) (*connect.Response[v1.ListElementsResponse], error)
	GetElement(context.Context, *connect.Request[v1.GetElementRequest]) (*connect.Response[v1.GetElementResponse], error)
	CreateElement(context.Context, *connect.Request[v1.CreateElementRequest]) (*connect.Response[v1.CreateElementResponse], error)
	UpdateElement(context.Context, *connect.Request[v1.UpdateElementRequest]) (*connect.Response[v1.UpdateElementResponse], error)
	ListElementPlacements(context.Context, *connect.Request[v1.ListElementPlacementsRequest]) (*connect.Response[v1.ListElementPlacementsResponse], error)
	// Placements
	ListPlacements(context.Context, *connect.Request[v1.ListPlacementsRequest]) (*connect.Response[v1.ListPlacementsResponse], error)
	CreatePlacement(context.Context, *connect.Request[v1.CreatePlacementRequest]) (*connect.Response[v1.CreatePlacementResponse], error)
	UpdatePlacementPosition(context.Context, *connect.Request[v1.UpdatePlacementPositionRequest]) (*connect.Response[v1.UpdatePlacementPositionResponse], error)
	DeletePlacement(context.Context, *connect.Request[v1.DeletePlacementRequest]) (*connect.Response[v1.DeletePlacementResponse], error)
	// Connectors
	ListConnectors(context.Context, *connect.Request[v1.ListConnectorsRequest]) (*connect.Response[v1.ListConnectorsResponse], error)
	CreateConnector(context.Context, *connect.Request[v1.CreateConnectorRequest]) (*connect.Response[v1.CreateConnectorResponse], error)
	UpdateConnector(context.Context, *connect.Request[v1.UpdateConnectorRequest]) (*connect.Response[v1.UpdateConnectorResponse], error)
	// Element navigation
	ListElementNavigations(context.Context, *connect.Request[v1.ListElementNavigationsRequest]) (*connect.Response[v1.ListElementNavigationsResponse], error)
	CreateElementNavigation(context.Context, *connect.Request[v1.CreateElementNavigationRequest]) (*connect.Response[v1.CreateElementNavigationResponse], error)
	DeleteElementNavigationById(context.Context, *connect.Request[v1.DeleteElementNavigationByIdRequest]) (*connect.Response[v1.DeleteElementNavigationByIdResponse], error)
	// View Layers
	ListViewLayers(context.Context, *connect.Request[v1.ListViewLayersRequest]) (*connect.Response[v1.ListViewLayersResponse], error)
	CreateViewLayer(context.Context, *connect.Request[v1.CreateViewLayerRequest]) (*connect.Response[v1.CreateViewLayerResponse], error)
	UpdateViewLayer(context.Context, *connect.Request[v1.UpdateViewLayerRequest]) (*connect.Response[v1.UpdateViewLayerResponse], error)
	DeleteViewLayer(context.Context, *connect.Request[v1.DeleteViewLayerRequest]) (*connect.Response[v1.DeleteViewLayerResponse], error)
	// Comment Threads
	ListThreads(context.Context, *connect.Request[v1.ListThreadsRequest]) (*connect.Response[v1.ListThreadsResponse], error)
	CreateThread(context.Context, *connect.Request[v1.CreateThreadRequest]) (*connect.Response[v1.CreateThreadResponse], error)
	AddComment(context.Context, *connect.Request[v1.AddCommentRequest]) (*connect.Response[v1.AddCommentResponse], error)
	ResolveThread(context.Context, *connect.Request[v1.ResolveThreadRequest]) (*connect.Response[v1.ResolveThreadResponse], error)
	// Reactions
	ListReactions(context.Context, *connect.Request[v1.ListReactionsRequest]) (*connect.Response[v1.ListReactionsResponse], error)
	ToggleReaction(context.Context, *connect.Request[v1.ToggleReactionRequest]) (*connect.Response[v1.ToggleReactionResponse], error)
}

